def self.version()
  result = Blazen.rust_call(:uniffi_blazen_uniffi_fn_func_version,)
  return result.consumeIntoString
end


  
  

def self.complete_batch(model, requests, max_concurrency)
    model = model
    (CompletionModel.uniffi_check_lower model)
    
    requests = requests
    RustBuffer.check_lower_SequenceTypeCompletionRequest(requests)
    
    max_concurrency = Blazen::uniffi_in_range(max_concurrency, "u32", 0, 2**32)
    
    
  result = Blazen.rust_call_with_error(BlazenError,:uniffi_blazen_uniffi_fn_func_complete_batch,(CompletionModel.uniffi_lower model),RustBuffer.alloc_from_SequenceTypeCompletionRequest(requests),max_concurrency)
  return result.consumeIntoTypeBatchResult
end


  
  

def self.complete_batch_blocking(model, requests, max_concurrency)
    model = model
    (CompletionModel.uniffi_check_lower model)
    
    requests = requests
    RustBuffer.check_lower_SequenceTypeCompletionRequest(requests)
    
    max_concurrency = Blazen::uniffi_in_range(max_concurrency, "u32", 0, 2**32)
    
    
  result = Blazen.rust_call_with_error(BlazenError,:uniffi_blazen_uniffi_fn_func_complete_batch_blocking,(CompletionModel.uniffi_lower model),RustBuffer.alloc_from_SequenceTypeCompletionRequest(requests),max_concurrency)
  return result.consumeIntoTypeBatchResult
end


  
  

def self.new_diffusion_model(model_id, device, width, height, num_inference_steps, guidance_scale)
    model_id = (model_id ? Blazen::uniffi_utf8(model_id) : nil)
    RustBuffer.check_lower_Optionalstring(model_id)
    
    device = (device ? Blazen::uniffi_utf8(device) : nil)
