    result = Blazen.rust_call_with_error(BlazenError,:uniffi_blazen_uniffi_fn_method_workflowbuilder_step,uniffi_clone_handle(),RustBuffer.allocFromString(name),RustBuffer.alloc_from_Sequencestring(accepts),RustBuffer.alloc_from_Sequencestring(emits),(StepHandler.uniffi_lower handler))
